insert into public.demo_event_impacts (event_id, ticker, tier, direction, reasoning, pct_change, price, reaction_date) values
  ('evt_001', 'XOM', 'direct', 'up', 'Strikes on a major oil-producing nation raise the risk of supply disruption near the Gulf. Crude prices climb, which flows straight into ExxonMobil upstream revenue and refining margins — a mechanical, business-level link.', 1.127869652920082, 154.22000122070312, '2026-03-02'),
  ('evt_001', 'DAL', 'direct', 'down', 'Higher crude feeds directly into jet-fuel prices, Delta''s single largest variable cost. Fuel-cost exposure is a direct P&L hit, so the stock sells off on the supply-shock headline.', -2.2069969795957234, 64.25, '2026-03-02'),
  ('evt_002', 'XOM', 'direct', 'up', '~20% of seaborne oil transits the Strait of Hormuz. Disruption fear spikes crude; XOM traded up as an integrated-oil beneficiary of higher prices.', 1.127869652920082, 154.22000122070312, '2026-03-02'),
  ('evt_002', 'DAL', 'direct', 'down', 'Same Hormuz shock, opposite sign: a crude spike raises Delta’s projected jet-fuel bill, so shares fell on margin-compression fears.', -2.2069969795957234, 64.25, '2026-03-02'),
  ('evt_003', 'MSFT', 'indirect', 'down', 'Causal chain: oil spike → higher headline inflation expectations → market fears the Fed holds rates "higher for longer" → a higher discount rate compresses the valuation of long-duration megacap tech. No direct business link to oil — the transmission is purely macro/sentiment, hence indirect.', -2.5138705840217375, 356.7699890136719, '2026-03-27'),
  ('evt_003', 'NVDA', 'indirect', 'down', 'Same rate-fear mechanism as MSFT: a high-multiple AI hardware name de-rates when discount rates are expected to rise, with no oil-specific business exposure.', -2.17239027176487, 167.52000427246094, '2026-03-27'),
  ('evt_003', 'AMZN', 'indirect', 'down', 'Rate-driven multiple compression on a long-duration growth name. Secondary nuance: higher fuel could raise fulfillment costs, but the day’s move was macro-sentiment, not that direct link.', -3.9510442389467335, 199.33999633789062, '2026-03-27'),
  ('evt_003', 'TSLA', 'indirect', 'down', 'Caught in the broad rate-fear selloff rather than any oil-specific driver — indirect, sentiment-led.', -2.762623735986156, 361.8299865722656, '2026-03-27'),
  ('evt_003', 'GOOGL', 'indirect', 'down', 'Long-duration megacap caught in the same discount-rate de-rating. CNBC also tied the session’s tech losses to regulatory pressure on Meta and Google, which compounds the macro move but is a separate driver.', -2.342309830316321, 274.3399963378906, '2026-03-27'),
  ('evt_003', 'META', 'indirect', 'down', 'Same rate-fear de-rating as its megacap peers, with the session’s coverage additionally citing regulatory scrutiny weighing on Meta. Indirect: no oil-linked business exposure.', -3.985098476796351, 525.719970703125, '2026-03-27'),
  ('evt_003', 'NFLX', 'unrelated', 'none', 'A control case. Netflix closed essentially FLAT (+0.1%) while the Nasdaq fell 2.15% — the rate-driven de-rating that hit its megacap peers simply did not transmit here. Sweeping it into the selloff because it is "a tech stock" would be exactly the false pattern-matching this map exists to catch.', 0.11787463642443992, 93.43000030517578, '2026-03-27'),
  ('evt_003', 'V', 'indirect', 'down', 'Payments volume is pro-cyclical: an oil-driven inflation scare raises recession risk, which the market prices as slower consumer transaction growth. Indirect — a demand-expectation channel, not a cost line.', -3.2762772250249137, 295.5199890136719, '2026-03-27'),
  ('evt_003', 'AAPL', 'indirect', 'down', 'Apple fell with the tape (-1.6%) but by LESS than the Nasdaq’s -2.15% — it participated in the discount-rate de-rating without being the epicentre. Indirect: no oil-linked business exposure, and the underperformance-adjusted move is a market-beta effect rather than an Apple-specific one.', -1.6173025219509891, 248.8000030517578, '2026-03-27'),
  ('evt_003', 'JPM', 'indirect', 'down', 'The instructive one. The tidy thesis is "higher-for-longer rates help asset-sensitive banks," which would argue JPM should hold up — and it did NOT: it fell 3%, worse than the index. On a day when an oil shock raises recession odds, credit-loss fear outweighs the net-interest-margin benefit. Indirect, and a reminder that the textbook rate story loses to risk-off when growth is the worry.', -3.0240715948275185, 282.8399963378906, '2026-03-27'),
  ('evt_003', 'WMT', 'unrelated', 'up', 'The clean control case: Walmart ROSE (+0.6%) while the Nasdaq fell into correction. Defensive staples absorb the rotation out of long-duration growth in a recession-risk session, so the tech selloff is not a valid explanation for Walmart’s move — the causation runs the other way, if at all.', 0.5811090871658635, 122.88999938964844, '2026-03-27'),
  ('evt_003', 'LLY', 'indirect', 'down', 'Lilly fell about 2% with the broad market. Pharma cash flows are not driven by the oil/rate chain, so this is index-beta participation rather than a causal link — indirect, and it should not be read as the market repricing the drug franchise.', -2.0914169192447045, 878.239990234375, '2026-03-27'),
  ('evt_004', 'LLY', 'direct', 'up', 'A regulatory approval is the most mechanical catalyst there is: Foundayo is an ORAL GLP-1, which removes the injection barrier and the cold-chain constraint that cap the addressable market for injectables. Approval converts a pipeline asset into a revenue line — a direct, company-specific value event.', 3.7781183624260697, 954.52001953125, '2026-04-01'),
  ('evt_005', 'XOM', 'direct', 'down', 'A ceasefire plus the prospect of safe Hormuz transit unwinds the war-risk premium. U.S. crude fell from ~$117 to ~$95, and falling crude directly compresses integrated-oil revenue — the mirror image of the February spike trade.', -4.691600432917278, 156.22000122070312, '2026-04-08'),
  ('evt_005', 'DAL', 'direct', 'up', 'Same crude move, opposite sign: a sharp drop in oil directly cuts Delta’s projected jet-fuel bill, its largest variable cost, so the shares rallied on the improved margin outlook.', 3.7488555036684925, 68.08000183105469, '2026-04-08'),
  ('evt_006', 'JPM', 'direct', 'down', 'Net income of $16.5B (EPS $5.94) on revenue of $50.5B, up 10%, with a 23% return on tangible common equity and net interest income up 9% — and the stock still eased ~0.8% on the day. A beat that was already the consensus expectation is not a catalyst; the market had priced the strong quarter going in. Direct because this is JPMorgan’s own P&L, but note the sign: strong results and a positive stock reaction are NOT the same thing.', -0.8161175779035917, 311.1199951171875, '2026-04-14'),
  ('evt_007', 'NFLX', 'direct', 'down', 'Q1 revenue rose 16% to $12.25B on the March price increases (Standard to $19.99, Premium to $26.99) and an ad tier reaching 250M+ monthly active viewers — and the stock fell almost 10%. Growth of 16% is a deceleration for a company valued on continued acceleration, and Netflix has stopped reporting quarterly subscriber counts, which removes the metric bulls used to underwrite the multiple. Direct: this is Netflix’s own report, and it is the sharpest single-name reaction in this dataset — a beat on the top line is not a beat on expectations.', -9.722611808071644, 97.30999755859375, '2026-04-17'),
  ('evt_008', 'AAPL', 'direct', 'up', 'A CEO succession at the world’s most valuable company is a direct, company-specific governance event — and the market read it as continuity, not disruption: the stock ROSE ~1% on the announcement. Cook moves to executive chairman rather than leaving, hardware chief John Ternus was the long-groomed internal pick, and the board approved it unanimously. Succession risk that resolves cleanly removes an overhang instead of creating one.', 1.0435468645202763, 273.04998779296875, '2026-04-20'),
  ('evt_009', 'TSLA', 'direct', 'down', 'The best "same day, two causes" teaching case. Tesla BEAT on EPS ($0.41, +17% vs. estimates) with the strongest gross margin in five quarters, and initially popped 4% after hours. Then the CFO confirmed full-year capex above $25B — up from $20B and roughly triple 2025’s $8.6B — and the stock gave it all back, closing down 3.56%. The direct cause is the capex guidance in its own release, NOT the macro tape.', -3.5586199575237787, 373.7200012207031, '2026-04-23'),
  ('evt_010', 'V', 'direct', 'up', 'Net revenue of $11.2B, up 17% — the fastest growth since 2022 — with non-GAAP EPS of $3.31 beating consensus, plus $9.2B returned to shareholders and a fresh $20B repurchase authorization. Direct: Visa earns a toll on payment volume, so accelerating volume is a mechanical revenue link, not a sentiment read.', 8.263821069305195, 334.8599853515625, '2026-04-29'),
  ('evt_011', 'META', 'direct', 'down', 'Revenue grew 33% — the fastest since 2021 — and the stock still fell, because Meta raised 2026 capex guidance to $125–145B, nearly double 2025 and more than 2025 and 2024 combined. The market is pricing the free-cash-flow hit, not the revenue beat. Direct: this is Meta’s own guidance in its own release.', -8.550039214212493, 611.9099731445312, '2026-04-30'),
  ('evt_011', 'NVDA', 'indirect', 'down', 'The textbook logic says one company’s capex is another’s revenue — a customer spending $145B on AI should be GOOD for the accelerator vendor. It did not play out: Nvidia fell 4.6% the same session. When the market decides AI capex is value-destroying, it sells the spenders AND the suppliers, because the fear is that the spending itself gets cut. Indirect, and a live example of the obvious read-through failing.', -4.626041900014934, 199.57000732421875, '2026-04-30'),
  ('evt_011', 'AVGO', 'indirect', 'up', 'Broadcom counts Meta among its custom-AI-silicon customers, and it ROSE on the day even as Nvidia fell — a divergence worth noticing. Custom-ASIC exposure is read as a share-gain story (hyperscalers designing their own chips buy Broadcom, not Nvidia), so the same capex headline can cut opposite ways across two "AI chip" names. Indirect: a customer-spending read-through, not Broadcom’s own results.', 2.954736738947925, 417.42999267578125, '2026-04-30'),
  ('evt_012', 'GOOGL', 'direct', 'up', 'Revenue of $109.9B (+22%) beat the $107.2B consensus, EPS rose 82% to $5.11, and Google Cloud grew 63% to $20.03B with operating income tripling to $6.6B. Cloud backlog nearly doubled to $460B+. Direct: Alphabet’s own reported results — and the Cloud number is the one that answers the "will AI eat Search?" bear case.', 9.961703465838957, 384.79998779296875, '2026-04-30'),
  ('evt_013', 'MSFT', 'direct', 'down', 'Fiscal Q3 revenue of $61.9B (+13%), Azure up 31% on AI demand, and Azure guidance of 39–40% constant-currency growth against a 37% consensus — a beat on the metric that matters most, and the stock fell nearly 4%. The offset is the capex line: ~$190B guided for 2026, up 61%, with a $25B hit from higher component prices. Direct: Microsoft’s own results and guidance. Same shape as Meta and Amazon on the same day — the market is repricing AI spending, not AI revenue.', -3.9296972651300033, 407.7799987792969, '2026-04-30'),
  ('evt_014', 'AMZN', 'direct', 'up', 'EPS of $2.78 against a $1.64 estimate, with AWS up 28% to $37.59B — its fastest growth in over three years. Amazon closed higher, and that is the contrast worth studying: Microsoft and Meta reported the SAME day with the same enormous capex ($190B and $145B) and both fell, while Amazon’s ~$200B plan was forgiven because the cloud acceleration gave the market something to buy. The capex fear is real (trailing free cash flow is down 95% to $1.2B) — it just needed a growth number to outweigh it.', 0.7679398373068795, 265.05999755859375, '2026-04-30'),
  ('evt_016', 'LLY', 'direct', 'up', 'Revenue rose 56% to $19.8B with non-GAAP EPS of $8.55 well ahead of expectations, driven by Mounjaro ($8.66B, +125%) and Zepbound ($4.16B). Management raised full-year guidance to $82–85B. Direct: the incretin franchise IS the company’s P&L right now, and the raise is management’s own guidance.', 9.79663672427485, 934.5999755859375, '2026-04-30'),
  ('evt_015', 'AAPL', 'direct', 'up', 'Record March quarter: revenue $111.2B (+17%), EPS $2.01 (+22%), gross margin 49.3% vs. 47.1% a year earlier, with double-digit growth in every geographic segment and an iPhone March-quarter record on iPhone 17 demand. The board added $100B to the repurchase authorization and raised the dividend. Direct: Apple’s own reported results.', 3.2393618379240534, 280.1400146484375, '2026-05-01'),
  ('evt_017', 'NVDA', 'direct', 'down', 'A record quarter that still sold off — the classic "buy the rumor, sell the news." Revenue of $81.6B (+85% YoY, +20% QoQ) with Data Center at $75.2B (+92%), 75% gross margins, an added $80B of buyback authorization and the dividend raised from $0.01 to $0.25. The beat was real but modest against a stock priced at ~30x forward earnings that had already run 13.7% into the print, so positioning — not the fundamentals — drove the reaction. Direct: Nvidia’s own results.', -1.7720529342800742, 219.50999450683594, '2026-05-21'),
  ('evt_017', 'AVGO', 'indirect', 'down', 'Broadcom reported nothing here, but Nvidia’s print is the sector’s sentiment barometer: when the AI bellwether sells off on positioning, high-beta AI-silicon peers de-rate with it. Indirect — a read-across, not a business link.', -0.7635968898018578, 414.57000732421875, '2026-05-21'),
  ('evt_018', 'WMT', 'direct', 'down', 'The headline looks fine — revenue $177.75B, net sales +7.1%, net income +18.8%, e-commerce +26% — and the stock fell 7.3%, its worst move in this dataset. Look at the operating line instead: operating income grew just 5%, and higher fuel costs across distribution and fulfilment cut 250 basis points off that growth. This is the Iran oil shock arriving on a retailer’s income statement — the same crude spike that lifts XOM is a direct cost for the company that has to move the goods. Sales growth you cannot convert into profit is not a good quarter.', -7.267871090584144, 121.33999633789062, '2026-05-21'),
  ('evt_019', 'XOM', 'direct', 'down', 'Crude 20% off its 2026 high as ceasefire optimism drains the war-risk premium. Lower realized prices feed straight through to upstream revenue — the direct, mechanical link, running in reverse from February.', -1.1567856078975236, 145.25999450683594, '2026-05-29'),
  ('evt_019', 'DAL', 'indirect', 'none', 'The mechanism is real — a 20% retreat in crude cuts Delta’s largest variable cost — but Delta closed FLAT on the day, so the benefit did not show up in the tape. The ceasefire optimism had been building for weeks (see the April 8 pause), so the fuel-cost relief was already priced in by the time this headline landed. Marked indirect precisely because the expected reaction did not materialise: a valid mechanism is not the same as a same-day catalyst.', -0.012116022663066635, 82.4800033569336, '2026-05-29'),
  ('evt_020', 'AVGO', 'direct', 'down', 'Record quarter — revenue $22.2B (+48%), AI semiconductor revenue $10.8B (+143%) — and the shares fell anyway because guidance did not clear an extremely high bar. This is the same lesson as Nvidia’s print two weeks earlier: when a stock is priced for perfection, "excellent" reads as a miss. Direct: Broadcom’s own results and guidance.', -12.586859324621807, 418.9100036621094, '2026-06-04'),
  ('evt_021', 'XOM', 'direct', 'down', 'A confirmed framework — extending the ceasefire and reopening the Strait of Hormuz to shipping — removes the war-risk premium from crude. Brent fell below $80 for the first time since March. Falling crude directly compresses XOM’s upstream revenue.', -4.142572998740872, 140.9199981689453, '2026-06-15'),
  ('evt_021', 'DAL', 'direct', 'up', 'Reopening Hormuz restores an estimated 14 million barrels/day to the market. Cheaper crude means a cheaper jet-fuel bill — a direct, mechanical improvement to Delta’s largest cost line.', 1.2159910497444621, 84.06999969482422, '2026-06-15'),
  ('evt_022', 'JPM', 'direct', 'up', 'The FOMC held at 3.50–3.75% but erased its remaining 2026 cut and now projects rates ENDING the year higher, with 17 of 18 officials seeing inflation risk to the upside. For an asset-sensitive bank this is a direct earnings input: loans reprice upward faster than deposits, expanding net interest income. The mechanism that hurts long-duration equities is the one that pays JPMorgan.', 0.7006029788045043, 333.4599914550781, '2026-06-17'),
  ('evt_022', 'MSFT', 'indirect', 'down', 'A higher-for-longer path raises the discount rate applied to distant cash flows, which compresses the multiple on long-duration megacap tech. Indirect: nothing about Microsoft’s business changed on the day — only the rate used to value it.', -3.7884324248678087, 378.9100036621094, '2026-06-17'),
  ('evt_022', 'GOOGL', 'indirect', 'down', 'Same discount-rate channel as its megacap peers. A hawkish dot-plot flip de-rates growth multiples regardless of the underlying business, which is why this is indirect rather than direct.', -2.5344920174355323, 363.7900085449219, '2026-06-17'),
  ('evt_022', 'META', 'indirect', 'down', 'Rate-driven multiple compression, and it stings more here because Meta is spending $125–145B on AI capex — a higher discount rate makes a heavy, back-loaded investment program look more expensive in present-value terms.', -5.436431197128365, 567.5800170898438, '2026-06-17'),
  ('evt_022', 'AMZN', 'indirect', 'down', 'Long-duration growth name carrying a ~$200B capex plan; a higher-for-longer rate path lowers the present value of the payoff from that spend. Indirect — a valuation channel, not an operating one.', -3.4552845528455287, 237.5, '2026-06-17'),
  ('evt_022', 'NFLX', 'indirect', 'down', 'High-multiple growth equity de-rates when the terminal discount rate rises. Netflix’s subscriber economics did not change on the day — only what the market will pay for them.', -2.235775036761043, 76.95999908447266, '2026-06-17'),
  ('evt_022', 'V', 'indirect', 'down', 'A hawkish turn tightens financial conditions, which the market reads as slower consumer spending ahead — and Visa is paid on transaction volume. The chain (rates → consumer demand → payment volume) is real but macro-mediated, hence indirect.', -0.8225234973995197, 330.3800048828125, '2026-06-17'),
  ('evt_022', 'WMT', 'indirect', 'down', 'The defensive-rotation thesis says staples should absorb money fleeing growth when the Fed turns hawkish — and here it FAILED: Walmart fell 2.4% with the market. Compare this to March 27, when the same thesis worked and Walmart rose while the Nasdaq corrected. Same stock, same playbook, opposite outcome. A tightening cycle eventually threatens the consumer that staples sell to, and defensiveness is relative, not absolute.', -2.39610142537238, 118.12999725341797, '2026-06-17'),
  ('evt_022', 'LLY', 'unrelated', 'down', 'The control case for this event. Lilly drifted down under 1% — noise, and far less than the rate-sensitive names. Its value is driven by the incretin franchise ramp and FDA milestones, not by the discount-rate mechanism that repriced tech. Treating a same-day Fed headline as the cause of a sub-1% move would be exactly the pattern-matching error this map exists to prevent.', -0.9354120267260578, 1112, '2026-06-17'),
  ('evt_023', 'XOM', 'direct', 'up', 'The de-escalation trade partially reverses: postponed talks re-inject supply risk into crude, and a higher price directly lifts integrated-oil revenue. The whole Feb–Jul arc is one oscillating risk premium, which is why these oil events all link to one another.', 0.47892291836719325, 138.47000122070312, '2026-06-22'),
  ('evt_023', 'DAL', 'unrelated', 'up', 'The link broke. Crude rose on the postponed talks — which "should" raise Delta’s jet-fuel bill and push the stock down — and Delta ROSE 2.1% instead. When the mechanical chain and the tape disagree this plainly, the honest answer is that the oil headline did not drive Delta that session; something else did. Flagged unrelated rather than forcing the story to fit.', 2.0669967420545947, 85.91999816894531, '2026-06-22'),
  ('evt_024', 'NVDA', 'indirect', 'down', 'A broad, AI-and-chip-led global selloff days after the Fed’s hawkish flip. Nvidia is the highest-beta expression of the AI trade, so it takes the largest hit in a sector de-rating. Indirect: no company-specific news — this is positioning unwinding across the theme.', -4.126528091164557, 200.0399932861328, '2026-06-23'),
  ('evt_024', 'AVGO', 'indirect', 'down', 'Same AI-complex unwind. Broadcom trades as an AI-silicon proxy, so it falls with the theme rather than on anything in its own business.', -3.055112038648594, 380.1499938964844, '2026-06-23'),
  ('evt_024', 'GOOGL', 'indirect', 'down', 'Named in the coverage as one of the megacaps leading the Nasdaq-100 lower. Indirect — a theme-wide de-rating, not an Alphabet-specific catalyst.', -1.0152104402096156, 346.1300048828125, '2026-06-23'),
  ('evt_024', 'META', 'indirect', 'down', 'Caught in the same big-tech unwind. The market is re-pricing the entire "spend enormous capex on AI now, earn later" trade, and Meta has the most aggressive capex ramp of the group.', -0.2926245367292342, 562.2000122070312, '2026-06-23'),
  ('evt_024', 'MSFT', 'unrelated', 'up', 'Read the label, not the headline. This was an AI-and-CHIP-led selloff, and Microsoft actually ROSE 1.8% through it. "Global tech sell-off" is a headline, not a mechanism: the money coming out of semiconductors did not come out of enterprise software. Sweeping MSFT into this event because it is a tech stock would be precisely the false attribution this map is built to expose.', 1.7967022838005193, 373.94000244140625, '2026-06-23'),
  ('evt_024', 'AMZN', 'unrelated', 'up', 'Amazon also closed HIGHER (+0.6%) during the "global tech sell-off." The unwind was concentrated in AI hardware and chip names; Amazon’s retail-plus-cloud mix did not participate. Flagged unrelated — a same-day tech headline is not evidence of causation for a stock that went the other way.', 0.5670378290686527, 234.11000061035156, '2026-06-23'),
  ('evt_025', 'XOM', 'indirect', 'down', 'The reasoning stress-test. A fresh attack headline "should" push oil up and XOM with it — prices spiked, then EASED back as the market weighted ample spare capacity and soft demand over the incident. The naive "conflict → oil up → XOM up" chain did NOT hold. Flagged indirect precisely because the mechanical link broke down; an honest model has to be able to say the obvious story failed.', -0.7342855276018787, 136.5399932861328, '2026-06-26'),
  ('evt_025', 'DAL', 'indirect', 'up', 'With crude fading despite the attack, Delta’s fuel outlook was not damaged the way the headline implies. The counterintuitive setup makes this indirect and low-confidence rather than a clean direct read.', 0.4994018905922799, 92.56999969482422, '2026-06-26'),
  ('evt_026', 'TSLA', 'unrelated', 'down', 'The most uncomfortable case in this dataset, and the one worth sitting with. Tesla delivered 480,126 vehicles against a ~406,600 consensus — a colossal beat, up 25% year-over-year — and the stock fell 7.5% that session. Deliveries are the cleanest read on Tesla’s revenue line, so the naive model says "huge beat → stock up." It did not happen. Because the move went hard against the news, this event is flagged UNRELATED to the decline: whatever drove that 7.5% drop, the delivery number is not it, and inventing a story to reconcile them would be exactly the fabrication this map exists to prevent. The honest statement is that the beat is real, the drop is real, and the delivery report does not explain it.', -7.488825887632451, 393.45001220703125, '2026-07-02'),
  ('evt_027', 'XOM', 'direct', 'up', 'Three vessels struck near Hormuz in under 24 hours, and the U.S. then revoked Iran’s oil-sale license. Brent settled 3% higher at $74.16 and popped 5.6% to $76.04 after hours. Tighter supply expectations lift realized prices, directly lifting XOM — the same causal shape as the March 2 Hormuz event.', 3.847845137832357, 141.69000244140625, '2026-07-07'),
  ('evt_027', 'DAL', 'direct', 'down', 'Renewed crude spike raises jet-fuel cost expectations — a direct hit to Delta’s largest variable cost, and the mirror image of the XOM trade.', -3.326792148347784, 88.62999725341797, '2026-07-07'),
  ('evt_028', 'NVDA', 'direct', 'none', 'Two lessons in one. FIRST, attribution: Nvidia moved on the same day as the tanker-attack oil headline, so a model that blames the biggest story of the day would tie it to Iran. Wrong — the Nvidia-specific news is competitive: Reuters reported DeepSeek is designing its own SMIC-fabricated inference chip to cut its dependence on Nvidia and Huawei. SECOND, data limits: Nvidia dipped intraday on the report but CLOSED slightly higher (+0.7%), so the daily close this system measures shows almost nothing. The reported dip is real and the flat close is real; a daily bar simply cannot see an intraday reaction. Direction is marked "none" rather than pretending the close confirms the story.', 0.7056965494693367, 196.92999267578125, '2026-07-07'),
  ('evt_028', 'AVGO', 'indirect', 'down', 'Every large AI customer that designs its own silicon is a customer that buys fewer merchant accelerators. The DeepSeek report is a datapoint in the broader in-house-chip trend, which pressures the whole merchant AI-silicon complex. Indirect — Broadcom is not named in the report.', -0.8344464209997506, 370.7799987792969, '2026-07-07');
